            'tips' => [
                ['num' => 98, 'text' => 'Kuny skalní jsou jedni z nejnebezpečnějších predátorů domácích slepic. Jsou nočním lovcem a dokáží se protáhnout otvorem o průměru pouhých 3–4 cm. Typické chování: pronikne do kurníku, zabije několik slepic najednou (i ty, které nesežere – instinkt „zabíjení do zásoby"), odnáší si obvykle jen jednu. Kousnutí do krku nebo hlavy.'],
                ['num' => 99, 'text' => 'Lišky jsou chytré, přizpůsobivé a fyzicky zdatné. Dokáží podhrabat plot za několik minut a přeskočit oplocení do výšky 1,5 metru. V období péče o mláďata mohou útočit i za denního světla. Podobně jako kuny dokáží při proniknutí do kurníku vyhubit celé hejno během minut. Stačí malá chyba – nezavřená dvířka, děravé pletivo, plot bez dostatečné hloubky.'],
                ['num' => 100, 'text' => 'Tchoři se chovají podobně jako kuny – vnikají malými otvory a zabíjejí kousnutím do krku. Navíc zanechávají typický pronikavý zápach.'],
                ['num' => 101, 'text' => 'Draví ptáci (jestřábi, káňata, výři) útočí shora, zejména na menší slepice a kuřata. Jestřábi loví ve dne, výři v noci. Otevřené výběhy bez zastřešení jsou pro ně ideální příležitostí.'],
                ['num' => 102, 'text' => 'Hadi se živí především vejci, která kradou z hnízd. Menší hadi mohou pokousat slepice, zejména kuřata. Vnikají do kurníku skulinami a ukrývají se v teplých, tmavých místech.'],
                ['num' => 103, 'text' => 'Potkani a myši kradou vejce a krmení, ale mohou také napadat malá kuřata. Navíc přenášejí nemoci (salmonelóza, leptospiróza). Přitahuje je nezabezpečené krmivo a zbytky potravy kolem kurníku.'],
