            'subsections' => [
                [
                    'id' => 'jak-slepice-chranit',
                    'title' => 'Jak slepice chránit',
                    'tips' => [
                        ['num' => 104, 'text' => 'Kurník musí být bezespárový – žádné skuliny, díry ani praskliny. Používejte pletivo s malými oky (ideálně 1×1 cm nebo menší), protože kuny a lasice se protáhnou i otvory, které se zdají nemožné. Větší pletivo (např. králičí drát) může udržet slepice uvnitř, ale nezastaví menší predátory.'],
                        ['num' => 105, 'text' => 'Automatická dvířka do kurníku jsou jednou z nejlepších investic pro chovatele. Zavírají se a otevírají automaticky podle nastaveného času nebo intenzity světla, čímž eliminují riziko, že zapomenete kurník na noc zavřít. Moderní varianty mají bezpečnostní funkci, která zabrání skřípnutí slepice.'],
                        ['num' => 106, 'text' => 'Oplocení výběhu by mělo být minimálně 180 cm vysoké a zakopané alespoň 30–50 cm pod zem proti podhrabání. U lišek se doporučuje zakopat pletivo ohnuté do tvaru písmene L směrem ven od výběhu – liška kopající podél plotu narazí na pletivo a vzdá to.'],
                        ['num' => 107, 'text' => 'Zastřešení výběhu sítí proti ptákům chrání před útoky dravců shora. Nemusíte zastřešit celý výběh – stačí část, kde se slepice nejčastěji zdržují (kolem krmítka, napáječky). Síť zároveň zabrání přelétání slepic přes plot a vniknutí volně žijících ptáků, kteří mohou přenášet nemoci.'],
                        ['num' => 108, 'text' => 'Kohout funguje jako přirozený strážce hejna. Aktivně sleduje okolí, upozorní hejno varovným voláním na blížící se nebezpečí a dá slepicím signál ke schování. V případě útoku menšího predátora se může i bránit. Není to stoprocentní ochrana, ale významně zvyšuje šance hejna.'],
                        ['num' => 109, 'text' => 'Dobře vycvičený pes může být velmi účinným ochráncem. Jeho přirozený instinkt chránit svůj prostor a hlasité štěkání dokáží predátory odradit. Důležité je psa správně vycvičit, aby slepice nepovažoval za kořist.'],
                        ['num' => 110, 'text' => 'Krmivo vždy skladujte v uzavřených nádobách (plastové sudy s víkem, kovové kontejnery) – nezabezpečené krmivo přitahuje hlodavce, kteří mohou přilákat i větší predátory (kuny, lišky). Zbytky krmení nevylévejte kolem kurníku.'],
                        ['num' => 111, 'text' => 'Pravidelně kontrolujte stav oplocení, zámků a dvířek – zejména před nocí. Predátoři systematicky hledají slabá místa a testují oplocení. Poškozené pletivo, uvolněné sloupky nebo nefunkční zámky jsou pozvánkou.'],
